Day1 ({bars.index[i-2].date()}): change={day1_change:.2f}%, body_ratio={day1_body_ratio:.1%}\")\n                    print(f\"Day2 ({bars.index[i-1].date()}): change={day2_change:.2f}%\")\n                    print(f\"Day3 ({bars.index[i].date()}): change={day3_change:.2f}%, body_ratio={day3_body_ratio:.1%}\")\n                    print(f\"Day3 close {day3['close']:.2f} > Day1 midpoint {day1_midpoint:.2f}: {day3['close'] > day1_midpoint}\")\n                    \n                    # Check MA60\n                    ma60 = bars.iloc[i-59:i+1]['close'].mean()\n                    print(f\"MA60={ma60:.2f}, 90%={ma60*0.9:.2f}, Day3 close={day3['close']:.2f}, Low position: {day3['close'] < ma60*0.9}\")\n                    \n                    # Check 5-day validation\n                    pattern_low = min(day1['low'], day2['low'], day3['low'])\n                    next_5_low = bars.iloc[i+1:i+6]['low'].min()\n                    print(f\"Pattern low={pattern_low:.2f}, Next 5-day low={next_5_low:.2f}, Valid: {next_5_low >= pattern_low}\")\n                    \n                    # 5-day gain\n                    day8 = bars.iloc[i+5]\n                    gain = (day8['close'] - day3['close']) / day3['close'] * 100\n                    print(f\"5-day gain: {gain:.2f}%\")\n                break\n    except Exception as e:\n        print(f\"Error: {e}\")\nEOF\n"} {}
